import{_ as t,o as a,c as o,ag as r}from"./chunks/framework.NIzFHKo_.js";const u=JSON.parse('{"title":"Exports","description":"","frontmatter":{"uid":"81566a33-409b-4af2-bf79-f84a8cb99d36 ... ..."},"headers":[],"relativePath":"10_core/30_data/140_exports.md","filePath":"10_core/30_data/140_exports.md"}'),d={name:"10_core/30_data/140_exports.md"};function s(c,e,i,n,l,p){return a(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="exports" tabindex="-1">Exports <a class="header-anchor" href="#exports" aria-label="Permalink to &quot;Exports&quot;">​</a></h1><h2 id="exports-are-non-canonical" tabindex="-1">Exports are Non-Canonical <a class="header-anchor" href="#exports-are-non-canonical" aria-label="Permalink to &quot;Exports are Non-Canonical&quot;">​</a></h2><blockquote><p>Exports are derived outputs generated from canonical records. They are <strong>not</strong> truth sources.</p></blockquote><p>An export is always regeneratable from its source canonical records. If regenerating an export produces different results, the <strong>canonical records</strong> are the authority — not the export.</p><h2 id="export-types" tabindex="-1">Export Types <a class="header-anchor" href="#export-types" aria-label="Permalink to &quot;Export Types&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Export Type</th><th>Source</th><th>Format</th></tr></thead><tbody><tr><td>Case summary reports</td><td><code>qicase</code> records</td><td>PDF, Markdown</td></tr><tr><td>Extracted text</td><td><code>qiarchive.archive_chunks</code></td><td>Plain text, JSON</td></tr><tr><td>Embedding snapshots</td><td><code>qiarchive.archive_chunks.embedding</code></td><td>Parquet, JSON</td></tr><tr><td>Graph exports</td><td><code>qigraph.edges</code> + <code>qigraph.master_index</code></td><td>GraphML, JSON</td></tr><tr><td>Financial reports</td><td><code>qihome.expenses</code>, <code>qitax.returns</code></td><td>PDF, CSV</td></tr><tr><td>AI chat transcripts</td><td><code>qially.sessions</code>, <code>qially.messages</code></td><td>Markdown, JSON</td></tr></tbody></table><h2 id="export-rules" tabindex="-1">Export Rules <a class="header-anchor" href="#export-rules" aria-label="Permalink to &quot;Export Rules&quot;">​</a></h2><ul><li>Exports must be clearly labeled as derived (not canonical)</li><li>Exports must include a reference to their source <code>canonical_id</code> or <code>archive_id</code></li><li>Exports must not be committed back to canonical tables</li><li>Exports may be cached but must be versioned and timestamped</li><li>Stale exports must be flagged, not silently used</li></ul><h2 id="export-location" tabindex="-1">Export Location <a class="header-anchor" href="#export-location" aria-label="Permalink to &quot;Export Location&quot;">​</a></h2><p>Exports should be stored outside the canonical database:</p><ul><li>Local: <code>C:/QiData/exports/</code> (temporary)</li><li>Cloud: A dedicated non-canonical storage bucket or folder</li><li>Never: back into a canonical schema table as if they were primary records</li></ul>',11)])])}const x=t(d,[["render",s]]);export{u as __pageData,x as default};
